--** ENUM **--
-- 쥬얼


-- 큐드
CREATE TYPE DayPeriod AS ENUM ('MORNING','EVENING');
CREATE TYPE MealType AS ENUM ('BREAKFAST','LUNCH','DINNER');
CREATE TYPE MealTiming AS ENUM ('BEFORE','AFTER');

-- 블링